  1→import { addMonths, format, parseISO, lastDayOfMonth } from 'date-fns';
  2→import type {
  3→  LoanInput,
  4→  PrePayment,
  5→  RateChange,
  6→  AmortizationRow,
  7→  AmortizationResult,
  8→  LoanSummary,
  9→} from '../types/loan';
 10→
 11→function getEmiDate(year: number, month: number, emiDay: number): Date {
 12→  const date = new Date(year, month, 1);
 13→  const lastDay = lastDayOfMonth(date).getDate();
 14→  const day = Math.min(emiDay, lastDay);
 15→  return new Date(year, month, day);
 16→}
 17→
 18→function groupPrePaymentsByMonth(
 19→  prePayments: PrePayment[]
 20→): Map<string, number> {
 21→  const map = new Map<string, number>();
 22→  for (const pp of prePayments) {
 23→    const key = format(parseISO(pp.date), 'yyyy-MM');
 24→    map.set(key, (map.get(key) || 0) + pp.amount);
 25→  }
 26→  return map;
 27→}
 28→
 29→function buildRateByMonth(
 30→  rateChanges: RateChange[]
 31→): Map<string, number> {
 32→  const map = new Map<string, number>();
 33→  for (const rc of rateChanges) {
 34→    const key = format(parseISO(rc.date), 'yyyy-MM');
 35→    map.set(key, rc.newRate); // last one wins if multiple in same month
 36→  }
 37→  return map;
 38→}
 39→
 40→export function calculateAmortization(
 41→  loan: LoanInput,
 42→  prePayments: PrePayment[],
 43→  rateChanges: RateChange[] = []
 44→): AmortizationResult {
 45→  let currentAnnualRate = loan.annualRate;
 46→  let monthlyRate = currentAnnualRate / 100 / 12;
 47→  const ppByMonth = groupPrePaymentsByMonth(prePayments);
 48→  // Sort rate changes by date and build lookup
 49→  const sortedRateChanges = [...rateChanges].sort(
 50→    (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()
 51→  );
 52→  const rateByMonth = buildRateByMonth(sortedRateChanges);
 53→
 54→  const startDate = parseISO(loan.startDate);
 55→  let outstanding = loan.principal;
 56→  const schedule: AmortizationRow[] = [];
 57→  let totalInterest = 0;
 58→  let totalPaid = 0;
 59→  let monthNum = 0;
 60→  let currentDate = getEmiDate(
 61→    startDate.getFullYear(),
 62→    startDate.getMonth(),
 63→    loan.emiDebitDay
 64→  );
 65→
 66→  // If start date is after the emi day in that month, move to next month
 67→  if (currentDate < startDate) {
 68→    currentDate = addMonths(currentDate, 1);
 69→    currentDate = getEmiDate(
 70→      currentDate.getFullYear(),
 71→      currentDate.getMonth(),
 72→      loan.emiDebitDay
 73→    );
 74→  }
 75→
 76→  const MAX_MONTHS = 600;
 77→
 78→  while (outstanding > 0.01 && monthNum < MAX_MONTHS) {
 79→    monthNum++;
 80→    const dateStr = format(currentDate, 'yyyy-MM-dd');
 81→    const monthKey = format(currentDate, 'yyyy-MM');
 82→    const openingBalance = outstanding;
 83→
 84→    // Check for rate change this month
 85→    const newRate = rateByMonth.get(monthKey);
 86→    if (newRate !== undefined) {
 87→      currentAnnualRate = newRate;
 88→      monthlyRate = currentAnnualRate / 100 / 12;
 89→    }
 90→
 91→    // Apply pre-payment BEFORE interest calculation
 92→    // In Indian home loans, pre-payment reduces the principal immediately,
 93→    // so interest from that point is calculated on the reduced balance.
 94→    let ppAmount = 0;
 95→    const scheduledPP = ppByMonth.get(monthKey) || 0;
 96→    if (scheduledPP > 0 && outstanding > 0.01) {
 97→      ppAmount = Math.min(scheduledPP, outstanding);
 98→      outstanding -= ppAmount;
 99→      totalPaid += ppAmount;
100→    }
101→
102→    const interest = outstanding * monthlyRate;
103→    let principalPortion: number;
104→    let emiPaid: number;
105→
106→    if (outstanding <= 0.01) {
107→      // Pre-payment already cleared the loan
108→      emiPaid = 0;
109→      principalPortion = 0;
110→    } else if (outstanding + interest <= loan.emi) {
111→      // Final partial EMI
112→      emiPaid = outstanding + interest;
113→      principalPortion = outstanding;
114→    } else {
115→      emiPaid = loan.emi;
116→      principalPortion = loan.emi - interest;
117→    }
118→
119→    outstanding -= principalPortion;
120→    totalInterest += interest;
121→    totalPaid += emiPaid;
122→
123→    // Round near-zero to zero
124→    if (outstanding < 0.01) outstanding = 0;
125→
126→    schedule.push({
127→      month: monthNum,
128→      date: dateStr,
129→      openingBalance: Math.round(openingBalance * 100) / 100,
130→      interestComponent: Math.round(interest * 100) / 100,
131→      principalComponent: Math.round(principalPortion * 100) / 100,
132→      prePayment: Math.round(ppAmount * 100) / 100,
133→      totalPayment: Math.round((emiPaid + ppAmount) * 100) / 100,
134→      closingBalance: Math.round(outstanding * 100) / 100,
135→      annualRate: currentAnnualRate,
136→    });
137→
138→    if (outstanding <= 0) break;
139→
140→    // Advance to next month
141→    currentDate = addMonths(currentDate, 1);
142→    currentDate = getEmiDate(
143→      currentDate.getFullYear(),
144→      currentDate.getMonth(),
145→      loan.emiDebitDay
146→    );
147→  }
148→
149→  const lastRow = schedule[schedule.length - 1];
150→  return {
151→    schedule,
152→    totalInterest: Math.round(totalInterest * 100) / 100,
153→    totalAmountPaid: Math.round(totalPaid * 100) / 100,
154→    closureDate: lastRow?.date || loan.startDate,
155→    totalMonths: schedule.length,
156→  };
157→}
158→
159→export function generateSummary(
160→  loan: LoanInput,
161→  prePayments: PrePayment[],
162→  rateChanges: RateChange[] = []
163→): LoanSummary {
164→  const withPrePayments = calculateAmortization(loan, prePayments, rateChanges);
165→  const withoutPrePayments = calculateAmortization(loan, [], rateChanges);
166→
167→  return {
168→    withPrePayments,
169→    withoutPrePayments,
170→    interestSaved:
171→      Math.round(
172→        (withoutPrePayments.totalInterest - withPrePayments.totalInterest) * 100
173→      ) / 100,
174→    monthsSaved: withoutPrePayments.totalMonths - withPrePayments.totalMonths,
175→  };
176→}
177→
178→export function validateLoan(loan: LoanInput): string | null {
179→  if (loan.principal <= 0) return 'Principal must be positive';
180→  if (loan.annualRate <= 0 || loan.annualRate > 50)
181→    return 'Interest rate must be between 0 and 50%';
182→  if (loan.emi <= 0) return 'EMI must be positive';
183→  if (loan.emiDebitDay < 1 || loan.emiDebitDay > 28)
184→    return 'EMI debit day must be between 1 and 28';
185→
186→  const firstMonthInterest = loan.principal * (loan.annualRate / 100 / 12);
187→  if (loan.emi <= firstMonthInterest) {
188→    return `EMI (${loan.emi}) must exceed first month's interest (${Math.round(firstMonthInterest)}) to repay the loan`;
189→  }
190→
191→  return null;
192→}
