 1→import type { LoanInput, LoanSummary } from '../types/loan';
 2→import { formatCurrency, formatDate } from '../utils/formatters';
 3→
 4→interface Props {
 5→  summary: LoanSummary;
 6→  loan: LoanInput;
 7→}
