 9→export function SummaryCards({ summary, loan }: Props) {
10→  const { withPrePayments: wp, withoutPrePayments: wop } = summary;
11→
12→  // Loan progress: how many months completed based on current date
13→  const now = new Date();
14→  const nowKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
15→  let monthsCompleted = 0;
16→  for (const row of wp.schedule) {
17→    if (row.date.substring(0, 7) <= nowKey) {
18→      monthsCompleted = row.month;
19→    } else {
20→      break;
21→    }
22→  }
23→  const principalRepaid =
24→    monthsCompleted > 0
25→      ? loan.principal - (wp.schedule[monthsCompleted - 1]?.closingBalance ?? 0)
26→      : 0;
27→  const progressPct = ((principalRepaid / loan.principal) * 100).toFixed(1);
28→
29→  const cards = [
30→    {
31→      label: 'Total Interest',
32→      value: formatCurrency(wp.totalInterest),
33→      sub: `Original: ${formatCurrency(wop.totalInterest)}`,
34→      color: 'bg-red-50 border-red-200',
35→    },
36→    {
37→      label: 'Total Amount Paid',
38→      value: formatCurrency(wp.totalAmountPaid),
39→      sub: `Original: ${formatCurrency(wop.totalAmountPaid)}`,
40→      color: 'bg-blue-50 border-blue-200',
41→    },
42→    {
43→      label: 'Loan Closure Date',
44→      value: formatDate(wp.closureDate),
45→      sub: `Original: ${formatDate(wop.closureDate)}`,
46→      color: 'bg-purple-50 border-purple-200',
47→    },
48→    {
49→      label: 'Interest Saved',
50→      value: formatCurrency(summary.interestSaved),
51→      sub: `${((summary.interestSaved / wop.totalInterest) * 100).toFixed(1)}% reduction`,
52→      color: 'bg-green-50 border-green-200',
53→    },
54→    {
55→      label: 'Months Saved',
56→      value: `${summary.monthsSaved} months`,
57→      sub: `${wp.totalMonths} vs ${wop.totalMonths} months`,
58→      color: 'bg-amber-50 border-amber-200',
59→    },
60→    {
61→      label: 'Interest-to-Principal',
62→      value: `${((wp.totalInterest / loan.principal) * 100).toFixed(1)}%`,
63→      sub: `Original: ${((wop.totalInterest / loan.principal) * 100).toFixed(1)}%`,
64→      color: 'bg-orange-50 border-orange-200',
65→    },
66→    {
67→      label: 'Effective Cost',
68→      value: `${(wp.totalAmountPaid / loan.principal).toFixed(2)}x`,
69→      sub: `You pay ${(wp.totalAmountPaid / loan.principal).toFixed(2)}x the borrowed amount`,
70→      color: 'bg-cyan-50 border-cyan-200',
71→    },
72→    {
73→      label: 'Loan Progress',
74→      value: `${progressPct}%`,
75→      sub: `${monthsCompleted} months completed out of ${wp.totalMonths}`,
76→      color: 'bg-emerald-50 border-emerald-200',
77→    },
78→  ];
79→
80→  return (
81→    <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
82→      {cards.map((card) => (
83→        <div key={card.label} className={`rounded-xl border p-4 ${card.color}`}>
84→          <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">{card.label}</p>
85→          <p className="mt-1 text-xl font-bold text-gray-900">{card.value}</p>
86→          <p className="mt-1 text-xs text-gray-500">{card.sub}</p>
87→        </div>
88→      ))}
89→    </div>
90→  );
91→}
