  1→import { useRef, useEffect } from 'react';
  2→import { format } from 'date-fns';
  3→import type { AmortizationRow } from '../types/loan';
  4→import { formatCurrency, formatDate } from '../utils/formatters';
  5→
  6→interface Props {
  7→  schedule: AmortizationRow[];
  8→  isSimulated?: boolean;
  9→  actualScheduleLength?: number;
 10→  plannedPPMonths?: Set<string>;
 11→}
 12→
 13→function getCurrentMonthKey(): string {
 14→  return format(new Date(), 'yyyy-MM');
 15→}
 16→
 17→export function AmortizationTable({
 18→  schedule,
 19→  isSimulated,
 20→  actualScheduleLength,
 21→  plannedPPMonths,
 22→}: Props) {
 23→  const currentMonthKey = getCurrentMonthKey();
 24→  const currentRowRef = useRef<HTMLTableRowElement>(null);
 25→
 26→  useEffect(() => {
 27→    if (currentRowRef.current) {
 28→      currentRowRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
 29→    }
 30→  }, [schedule]);
 31→
 32→  // Detect if rates change across the schedule
 33→  const hasRateChanges =
 34→    schedule.length > 1 &&
 35→    schedule.some((row, i) => i > 0 && row.annualRate !== schedule[i - 1].annualRate);
 36→
 37→  return (
 38→    <div className="rounded-xl border border-gray-200 bg-white shadow-sm">
 39→      <div className="p-6 pb-0">
 40→        <h2 className="text-lg font-semibold text-gray-900">
 41→          Amortization Schedule
 42→          {isSimulated && (
 43→            <span className="ml-2 text-sm font-normal text-amber-600">(simulated)</span>
 44→          )}
 45→        </h2>
 46→        <p className="text-sm text-gray-500 mt-1">
 47→          {schedule.length} months
 48→          {isSimulated && actualScheduleLength && actualScheduleLength !== schedule.length && (
 49→            <span className="text-amber-600"> (was {actualScheduleLength} months)</span>
 50→          )}
 51→        </p>
 52→      </div>
 53→      <div className="overflow-x-auto p-4">
 54→        <table className="w-full text-left text-sm">
 55→          <thead>
 56→            <tr className="border-b border-gray-200 text-gray-600">
 57→              <th className="pb-2 pr-3 font-medium">#</th>
 58→              <th className="pb-2 pr-3 font-medium">Date</th>
 59→              {hasRateChanges && <th className="pb-2 pr-3 font-medium text-right">Rate</th>}
 60→              <th className="pb-2 pr-3 font-medium text-right">Opening Bal.</th>
 61→              <th className="pb-2 pr-3 font-medium text-right">Interest</th>
 62→              <th className="pb-2 pr-3 font-medium text-right">Principal</th>
 63→              <th className="pb-2 pr-3 font-medium text-right">Pre-Payment</th>
 64→              <th className="pb-2 pr-3 font-medium text-right">Total Paid</th>
 65→              <th className="pb-2 pr-3 font-medium text-right">Total Interest Paid</th>
 66→              <th className="pb-2 pr-3 font-medium text-right">Total Principal Paid</th>
 67→              <th className="pb-2 font-medium text-right">Closing Bal.</th>
 68→            </tr>
 69→          </thead>
 70→          <tbody>
 71→            {(() => {
 72→              let cumulativeInterest = 0;
 73→              let cumulativePrincipal = 0;
 74→              return schedule.map((row) => {
 75→                cumulativeInterest += row.interestComponent;
 76→                cumulativePrincipal += row.principalComponent + row.prePayment;
 77→                const rowMonthKey = row.date.substring(0, 7); // yyyy-MM
 78→                const isCurrentMonth = rowMonthKey === currentMonthKey;
 79→                const rateChanged =
 80→                  hasRateChanges &&
 81→                  row.month > 1 &&
 82→                  row.annualRate !== schedule[row.month - 2]?.annualRate;
 83→                const isPlannedPP = plannedPPMonths?.has(rowMonthKey) && row.prePayment > 0;
 84→
 85→                let rowClass = 'border-b border-gray-100 last:border-0';
 86→                if (isCurrentMonth) {
 87→                  rowClass += ' bg-blue-100 ring-2 ring-blue-400 ring-inset';
 88→                } else if (isPlannedPP) {
 89→                  rowClass += ' bg-amber-50 border-l-4 border-l-amber-400';
 90→                } else if (row.prePayment > 0) {
 91→                  rowClass += ' bg-green-50';
 92→                } else if (rateChanged) {
 93→                  rowClass += ' bg-indigo-50';
 94→                }
 95→
 96→                return (
 97→                  <tr
 98→                    key={row.month}
 99→                    ref={isCurrentMonth ? currentRowRef : undefined}
100→                    className={rowClass}
101→                  >
102→                    <td className="py-2 pr-3 text-gray-500">
103→                      {isCurrentMonth ? (
104→                        <span className="inline-flex items-center gap-1">
105→                          {row.month}
106→                          <span className="rounded bg-blue-600 px-1.5 py-0.5 text-[10px] font-bold text-white leading-none">
107→                            NOW
108→                          </span>
109→                        </span>
110→                      ) : isPlannedPP ? (
111→                        <span className="inline-flex items-center gap-1">
112→                          {row.month}
113→                          <span className="rounded bg-amber-500 px-1.5 py-0.5 text-[10px] font-bold text-white leading-none">
114→                            PLAN
115→                          </span>
116→                        </span>
117→                      ) : (
118→                        row.month
119→                      )}
120→                    </td>
121→                    <td className="py-2 pr-3 whitespace-nowrap">{formatDate(row.date)}</td>
122→                    {hasRateChanges && (
123→                      <td
124→                        className={`py-2 pr-3 text-right tabular-nums ${rateChanged ? 'font-semibold text-indigo-700' : 'text-gray-500'}`}
125→                      >
126→                        {row.annualRate}%
127→                      </td>
128→                    )}
129→                    <td className="py-2 pr-3 text-right tabular-nums">
130→                      {formatCurrency(row.openingBalance)}
131→                    </td>
132→                    <td className="py-2 pr-3 text-right tabular-nums text-red-600">
133→                      {formatCurrency(row.interestComponent)}
134→                    </td>
135→                    <td className="py-2 pr-3 text-right tabular-nums text-green-700">
136→                      {formatCurrency(row.principalComponent)}
137→                    </td>
138→                    <td className="py-2 pr-3 text-right tabular-nums">
139→                      {row.prePayment > 0 ? (
140→                        <span
141→                          className={`font-medium ${isPlannedPP ? 'text-amber-600' : 'text-blue-600'}`}
142→                        >
143→                          {formatCurrency(row.prePayment)}
144→                        </span>
145→                      ) : (
146→                        <span className="text-gray-300">-</span>
147→                      )}
148→                    </td>
149→                    <td className="py-2 pr-3 text-right tabular-nums">
150→                      {formatCurrency(row.totalPayment)}
151→                    </td>
152→                    <td className="py-2 pr-3 text-right tabular-nums text-red-600">
153→                      {formatCurrency(cumulativeInterest)}
154→                    </td>
155→                    <td className="py-2 pr-3 text-right tabular-nums text-green-700">
156→                      {formatCurrency(cumulativePrincipal)}
157→                    </td>
158→                    <td className="py-2 text-right tabular-nums font-medium">
159→                      {formatCurrency(row.closingBalance)}
160→                    </td>
161→                  </tr>
162→                );
163→              });
164→            })()}
165→          </tbody>
166→        </table>
167→      </div>
168→    </div>
169→  );
170→}
