 21→export function BalanceChart({ summary, simulatedResult }: Props) {
 22→  const { withPrePayments, withoutPrePayments } = summary;
 23→
 24→  const currentMonthKey = format(new Date(), 'yyyy-MM');
 25→
 26→  const maxLen = Math.max(
 27→    withPrePayments.schedule.length,
 28→    withoutPrePayments.schedule.length,
 29→    simulatedResult?.schedule.length ?? 0,
 30→  );
 31→
 32→  let currentMonthIndex: number | null = null;
 33→
 34→  const data = Array.from({ length: maxLen }, (_, i) => {
 35→    const dateStr =
 36→      withoutPrePayments.schedule[i]?.date ??
 37→      withPrePayments.schedule[i]?.date ??
 38→      simulatedResult?.schedule[i]?.date ??
 39→      '';
 40→    const monthKey = dateStr.substring(0, 7);
 41→    if (monthKey === currentMonthKey) {
 42→      currentMonthIndex = i + 1;
 43→    }
 44→    const entry: Record<string, number | string> = {
 45→      month: i + 1,
 46→      label: dateStr ? formatDate(dateStr) : '',
 47→      withoutPP: withoutPrePayments.schedule[i]?.closingBalance ?? 0,
 48→      withPP: withPrePayments.schedule[i]?.closingBalance ?? 0,
 49→    };
 50→    if (simulatedResult) {
 51→      entry.simulated = simulatedResult.schedule[i]?.closingBalance ?? 0;
 52→    }
 53→    return entry;
 54→  });
 55→
 56→  return (
 57→    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
 58→      <h3 className="mb-4 text-lg font-semibold text-gray-900">Outstanding Balance Over Time</h3>
 59→      <ResponsiveContainer width="100%" height={350}>
 60→        <LineChart data={data}>
 61→          <CartesianGrid strokeDasharray="3 3" />
 62→          <XAxis dataKey="month" label={{ value: 'Month', position: 'insideBottom', offset: -5 }} />
 63→          <YAxis tickFormatter={(v) => formatCurrency(v)} width={100} />
 64→          <Tooltip
 65→            formatter={(value) => formatCurrency(Number(value))}
 66→            labelFormatter={(_: unknown, payload: readonly { payload?: { label?: string } }[]) =>
 67→              payload?.[0]?.payload?.label || ''
 68→            }
 69→          />
 70→          <Legend />
 71→          {currentMonthIndex !== null && (
 72→            <ReferenceLine
 73→              x={currentMonthIndex}
 74→              stroke="#2563eb"
 75→              strokeWidth={2}
 76→              strokeDasharray="4 4"
 77→              label={{ value: 'Now', position: 'top', fill: '#2563eb', fontWeight: 'bold' }}
 78→            />
 79→          )}
 80→          <Line
 81→            type="monotone"
 82→            dataKey="withoutPP"
 83→            name="Original Schedule"
 84→            stroke="#94a3b8"
 85→            strokeWidth={2}
 86→            dot={false}
 87→          />
 88→          <Line
 89→            type="monotone"
 90→            dataKey="withPP"
 91→            name="Actual (with adjustments)"
 92→            stroke="#2563eb"
 93→            strokeWidth={2}
 94→            dot={false}
 95→          />
 96→          {simulatedResult && (
 97→            <Line
 98→              type="monotone"
 99→              dataKey="simulated"
100→              name="Simulated (what-if)"
101→              stroke="#f59e0b"
102→              strokeWidth={2}
103→              strokeDasharray="6 3"
104→              dot={false}
105→            />
106→          )}
107→        </LineChart>
108→      </ResponsiveContainer>
109→    </div>
110→  );
111→}
