11→export function PaymentBreakupChart({ summary }: Props) {
12→  const { withPrePayments: wp } = summary;
13→  const principalPaid = wp.totalAmountPaid - wp.totalInterest;
14→
15→  const data = [
16→    { name: 'Principal', value: Math.round(principalPaid) },
17→    { name: 'Interest', value: Math.round(wp.totalInterest) },
18→  ];
19→
20→  const total = data[0].value + data[1].value;
21→
22→  const renderLabel = ({
23→    cx,
24→    cy,
25→    midAngle,
26→    innerRadius,
27→    outerRadius,
28→    index,
29→  }: {
30→    cx?: number;
31→    cy?: number;
32→    midAngle?: number;
33→    innerRadius?: number;
34→    outerRadius?: number;
35→    index?: number;
36→  }) => {
37→    const RADIAN = Math.PI / 180;
38→    const radius = (innerRadius ?? 0) + ((outerRadius ?? 0) - (innerRadius ?? 0)) * 0.5;
39→    const x = (cx ?? 0) + radius * Math.cos(-(midAngle ?? 0) * RADIAN);
40→    const y = (cy ?? 0) + radius * Math.sin(-(midAngle ?? 0) * RADIAN);
41→    const pct = ((data[index ?? 0].value / total) * 100).toFixed(1);
42→
43→    return (
44→      <text
45→        x={x}
46→        y={y}
47→        fill="white"
48→        textAnchor="middle"
49→        dominantBaseline="central"
50→        fontWeight="bold"
51→        fontSize={14}
52→      >
53→        {pct}%
54→      </text>
55→    );
56→  };
57→
58→  return (
59→    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
60→      <h3 className="mb-4 text-lg font-semibold text-gray-900">Payment Breakup</h3>
61→      <ResponsiveContainer width="100%" height={350}>
62→        <PieChart>
63→          <Pie
64→            data={data}
65→            cx="50%"
66→            cy="50%"
67→            outerRadius={130}
68→            dataKey="value"
69→            labelLine={false}
70→            label={renderLabel}
71→          >
72→            {data.map((_, index) => (
73→              <Cell key={index} fill={COLORS[index]} />
74→            ))}
75→          </Pie>
76→          <Tooltip formatter={(value) => formatCurrency(Number(value))} />
77→        </PieChart>
78→      </ResponsiveContainer>
79→      <div className="mt-2 flex justify-center gap-6 text-sm">
80→        <span className="flex items-center gap-1.5">
81→          <span className="inline-block h-3 w-3 rounded-full bg-green-500" />
82→          Principal: {formatCurrency(principalPaid)}
83→        </span>
84→        <span className="flex items-center gap-1.5">
85→          <span className="inline-block h-3 w-3 rounded-full bg-red-500" />
86→          Interest: {formatCurrency(wp.totalInterest)}
87→        </span>
88→      </div>
89→    </div>
90→  );
91→}
