              type="number"
              className={`${inputClass} pl-8`}
              value={principal}
              onChange={(e) => setPrincipal(e.target.value)}
              placeholder="10,00,000"
              required
              min="1"
            />
          </div>
        </div>
        <div>
          <label className={labelClass}>Annual Interest Rate</label>
          <div className="relative">
            <input
              type="number"
              className={`${inputClass} pr-8`}
              value={rate}
              onChange={(e) => setRate(e.target.value)}
              placeholder="8.5"
              required
              min="0.1"
              max="50"
              step="0.01"
            />
            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-sm text-slate-400">%</span>
          </div>
        </div>
        <div>
          <label className={labelClass}>Monthly EMI</label>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-sm text-slate-400">&#8377;</span>
            <input
              type="number"
              className={`${inputClass} pl-8`}
              value={emi}
              onChange={(e) => setEmi(e.target.value)}
              placeholder="8,678"
              required
              min="1"
            />
          </div>
        </div>
        <div>
          <label className={labelClass}>EMI Debit Day</label>
          <input
            type="number"
            className={inputClass}
            value={emiDay}
            onChange={(e) => setEmiDay(e.target.value)}
            required
            min="1"
            max="28"
          />
        </div>
        <div>
          <label className={labelClass}>Loan Start Date</label>
          <input type="date" className={inputClass} value={startDate} onChange={(e) => setStartDate(e.target.value)} required />
        </div>
        <div className="flex items-end">
          <button
            type="submit"
            className="w-full rounded-xl bg-gradient-to-r from-blue-600 to-indigo-600 px-6 py-2.5 text-sm font-semibold text-white shadow-md shadow-blue-600/20 transition-all hover:shadow-lg hover:shadow-blue-600/30 hover:brightness-110 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 active:scale-[0.98]"
          >
            {loan ? 'Update Analysis' : 'Analyse Loan'}
          </button>
        </div>
      </div>
    </form>
  );
}

