        <div
          key={card.label}
          className={`group rounded-2xl border p-5 transition-all hover:shadow-md hover:-translate-y-0.5 ${card.accent}`}
        >
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs font-semibold uppercase tracking-wider opacity-70">{card.label}</span>
            <div className={`flex h-8 w-8 items-center justify-center rounded-lg ${card.iconBg} transition-transform group-hover:scale-110`}>
              {card.icon}
            </div>
          </div>
          <p className="text-2xl font-bold tracking-tight">{card.value}</p>
          <p className="mt-1 text-xs opacity-60">{card.sub}</p>
          {'progress' in card && (
            <div className="mt-3 h-1.5 w-full rounded-full bg-black/5 overflow-hidden">
              <div
